logger = logging.getLogger()
logger.setLevel(os.getenv("LOG_LEVEL", "INFO").upper())

AWS_REGION = os.getenv("AWS_REGION") or os.getenv("AWS_DEFAULT_REGION") or "us-east-1"
RESULTS_BUCKET = os.getenv("RESULTS_BUCKET", "")  # if empty, writes back to source bucket
RESULTS_PREFIX = os.getenv("RESULTS_PREFIX", "processed/")
SNS_TOPIC_ARN = os.getenv("SNS_TOPIC_ARN", "")
MAX_BYTES = int(os.getenv("MAX_BYTES", str(25 * 1024 * 1024)))  # 25MB default

BOTO_CONFIG = Config(
    retries={"max_attempts": int(os.getenv("BOTO_MAX_ATTEMPTS", "10")), "mode": "standard"},
    region_name=AWS_REGION,
)

s3 = boto3.client("s3", config=BOTO_CONFIG)
sns = boto3.client("sns", config=BOTO_CONFIG)


def _now_iso():
    return datetime.now(timezone.utc).isoformat()


def _safe_json(obj):
    try:
        return json.dumps(obj, default=str, ensure_ascii=False)
    except Exception:
        return json.dumps({"_unserializable": True, "type": str(type(obj))})


def _publish_sns(subject, message, attributes=None):
    if not SNS_TOPIC_ARN:
        logger.info("SNS_TOPIC_ARN not set; skipping publish. subject=%s message=%s", subject, message)
        return None
    kwargs = {
        "TopicArn": SNS_TOPIC_ARN,
        "Subject": subject[:100],
        "Message": message if isinstance(message, str) else _safe_json(message),
    }
    if attributes:
        msg_attrs = {}
        for k, v in attributes.items():
            if v is None:
                continue
            msg_attrs[str(k)] = {"DataType": "String", "StringValue": str(v)}
        if msg_attrs:
            kwargs["MessageAttributes"] = msg_attrs
    resp = sns.publish(**kwargs)
    return resp.get("MessageId")


def _head_object(bucket, key):
    return s3.head_object(Bucket=bucket, Key=key)


def _get_object_bytes(bucket, key, max_bytes=MAX_BYTES):
    obj = s3.get_object(Bucket=bucket, Key=key)
    body = obj["Body"].read(max_bytes + 1)
    if len(body) > max_bytes:
        raise ValueError(f"Object too large (> {max_bytes} bytes): s3://{bucket}/{key}")
    return body, obj


def _put_json(bucket, key, payload, content_type="application/json"):
    data = payload if isinstance(payload, (bytes, bytearray)) else _safe_json(payload).encode("utf-8")
    s3.put_object(
        Bucket=bucket,
        Key=key,
        Body=data,
        ContentType=content_type,
        ServerSideEncryption=os.getenv("SSE", "") or None,
    )


def _is_image(content_type, key):
    if content_type and content_type.lower().startswith("image/"):
        return True
    ext = (key.rsplit(".", 1)[-1] if "." in key else "").lower()
    return ext in {"jpg", "jpeg", "png", "gif", "bmp", "tiff", "tif", "webp", "heic", "heif"}


def _basic_image_metrics(data):
    # Minimal "processing" without external deps: compute size and a simple checksum-like value.
    # For MVP, you can replace with Pillow/OpenCV later.
    size = len(data)
    sample = data[:4096]
    checksum = sum(sample) % 1000000007
    return {"bytes": size, "sample_checksum_mod": checksum}


def _result_key_for(source_key):
    base = source_key.rsplit("/", 1)[-1]
    stem = base.rsplit(".", 1)[0]
    uid = uuid.uuid4().hex
    return f"{RESULTS_PREFIX.rstrip('/')}/{stem}.{uid}.json"


def _parse_s3_event_records(event):
    records = event.get("Records") or []
    out = []
    for r in records:
        if r.get("eventSource") != "aws:s3":
            continue
        s3info = r.get("s3") or {}
        bucket = ((s3info.get("bucket") or {}).get("name")) or ""
        key = ((s3info.get("object") or {}).get("key")) or ""
        if key:
            key = unquote_plus(key)
        if bucket and key:
            out.append((bucket, key, r))
    return out


def handler(event, context):
    request_id = getattr(context, "aws_request_id", None)
    logger.info("start request_id=%s event=%s", request_id, _safe_json(event))

    records = _parse_s3_event_records(event)
    if not records:
        msg = {"status": "ignored", "reason": "no_s3_records", "request_id": request_id, "ts": _now_iso()}
        logger.warning(_safe_json(msg))
        return msg

    results = []
    for bucket, key, raw_record in records:
        item = {
            "request_id": request_id,
            "source_bucket": bucket,
            "source_key": key,
            "ts": _now_iso(),
            "status": "unknown",
        }

        try:
            head = _head_object(bucket, key)
            content_type = head.get("ContentType")
            content_length = head.get("ContentLength")
            etag = head.get("ETag")
            item.update(
                {
                    "content_type": content_type,
                    "content_length": content_length,
                    "etag": etag,
                }
            )

            if content_length is not None and content_length > MAX_BYTES:
                raise ValueError(f"Object too large (> {MAX_BYTES} bytes): {content_length}")

            if not _is_image(content_type, key):
                item["status"] = "skipped"
                item["reason"] = "not_an_image"
                logger.info("skip non-image s3://%s/%s content_type=%s", bucket, key, content_type)
                results.append(item)
                continue

            data, obj = _get_object_bytes(bucket, key, max_bytes=MAX_BYTES)
            metrics = _basic_image_metrics(data)

            result_bucket = RESULTS_BUCKET or bucket
            result_key = _result_key_for(key)

            payload = {
                "request_id": request_id,
                "source": {"bucket": bucket, "key": key},
                "result": {"bucket": result_bucket, "key": result_key},
                "observed": {
                    "content_type": content_type,
                    "content_length": content_length,
                    "etag": etag,
                    "last_modified": str(head.get("LastModified")) if head.get("LastModified") else None,
                },
                "metrics": metrics,
                "raw_record": raw_record,
                "ts": _now_iso(),
            }

            _put_json(result_bucket, result_key, payload)

            item.update(
                {
                    "status": "processed",
                    "result_bucket": result_bucket,
                    "result_key": result_key,
                    "metrics": metrics,
                }
            )

            msg_id = _publish_sns(
                subject="Image processed",
                message=payload,
                attributes={
                    "source_bucket": bucket,
                    "source_key": key,
                    "result_bucket": result_bucket,
                    "result_key": result_key,
                    "request_id": request_id,
                    "status": "processed",
                },
            )
            if msg_id:
                item["sns_message_id"] = msg_id

            logger.info("processed s3://%s/%s -> s3://%s/%s", bucket, key, result_bucket, result_key)

        except Exception as e:
            item["status"] = "error"
            item["error"] = {"type": type(e).__name__, "message": str(e)}
            item["traceback"] = traceback.format_exc()

            logger.error("error processing s3://%s/%s err=%s", bucket, key, str(e), exc_info=True)

            _publish_sns(
                subject="Image processing failed",
                message=item,
                attributes={
                    "source_bucket": bucket,
                    "source_key": key,
                    "request_id": request_id,
                    "status": "error",
                    "error_type": type(e).__name__,
                },
            )

        results.append(item)

    response = {"request_id": request_id, "count": len(results), "results": results, "ts": _now_iso()}
    logger.info("done request_id=%s response=%s", request_id, _safe_json(response))
    return response